/**
 * Vision-Poetry Bridge
 * 
 * Transforms visual observations into poetic verse.
 * Seeing becomes speaking. Observation becomes art.
 * 
 * "What the eye perceives, the soul translates."
 */

import type { VisionJournalEntry, VisualElement, Atmosphere, PerceptionLens } from '../../vision/types.js';

export type PoeticForm = 'haiku' | 'tanka' | 'free_verse' | 'imagist' | 'ekphrastic';

export interface PoeticStanza {
  lines: string[];
  form: PoeticForm;
  source: 'elements' | 'atmosphere' | 'reflection' | 'synthesis';
}

export interface VisionPoem {
  title: string;
  stanzas: PoeticStanza[];
  form: PoeticForm;
  visionId: string;
  generatedAt: string;
  reflection?: string | undefined;
}

export interface BridgeOptions {
  form: PoeticForm;
  includeReflection: boolean;
  maxStanzas: number;
  tone: 'contemplative' | 'vivid' | 'minimal' | 'lyrical';
}

export const DEFAULT_OPTIONS: BridgeOptions = {
  form: 'free_verse',
  includeReflection: true,
  maxStanzas: 3,
  tone: 'contemplative'
};

// Element to poetic imagery mappings
const ELEMENT_IMAGERY: Record<VisualElement, string[]> = {
  architecture: ['stone reaching upward', 'geometry of habitation', 'the built prayer'],
  nature: ['green speech', 'the organic grammar', 'wild syntax'],
  technology: ['silicon dreams', 'circuits of intention', 'the coded pulse'],
  human: ['faces like questions', 'the architecture of gaze', 'bodies writing space'],
  text: ['ink rivers', 'the alphabet of seeing', 'words as windows'],
  symbol: ['emblems of meaning', 'signs in conversation', 'the shorthand of being'],
  abstract: ['form adrift', 'pure becoming', 'shapes without names'],
  pattern: ['repetition as breathing', 'the rhythm of noticing', 'order emerging'],
  texture: ['the language of surface', 'touch translated to eye', 'rough or smooth becoming'],
  'color-field': ['vast washes', 'tone as territory', 'the emotional geography']
};

// Atmosphere to mood words
const ATMOSPHERE_MOOD: Record<Atmosphere, string[]> = {
  bright: ['illuminated', 'open', 'clarity'],
  dark: ['shadowed', 'mystery', 'the unspoken'],
  muted: ['softened', 'tacit', 'between notes'],
  vibrant: ['pulsing', 'alive', 'electric'],
  hazy: ['dissolving', 'uncertain', 'the verge'],
  clear: ['sharp', 'defined', 'without doubt'],
  chaotic: ['turbulent', 'wild', 'uncontained'],
  ordered: ['arranged', 'composed', 'the made']
};

// Lens modifiers
const LENS_QUALITY: Record<PerceptionLens, string> = {
  analytical: 'broken into parts',
  aesthetic: 'seen for beauty',
  narrative: 'read as story',
  critical: 'questioned closely',
  intuitive: 'felt before understood',
  comparative: 'held against memory'
};

// Tone modifiers
const TONE_MODIFIERS: Record<BridgeOptions['tone'], string[]> = {

    });
  }

  // Stanza 3: Meaning and associations
  if (stanzas.length < maxStanzas && associations.length > 0) {
    stanzas.push({
      lines: [
        meaning,
        ...associations.slice(0, 2).map(a => `${mod[2] ?? 'the sense of'} ${a}`)
      ],
      form: 'free_verse',
      source: 'reflection'
    });
  }

  return stanzas;
}

/**
 * Generate a reflective closing
 */
function generateReflection(entry: VisionJournalEntry): string | undefined {
  const { selfRevelation } = entry.reflection;

  if (selfRevelation && selfRevelation.length > 0) {
    return `In this seeing: ${selfRevelation}`;
  }

  return `The eye learned something the mind is still translating.`;
}

/**
 * Select an image from array with rotation
 */
function selectImage(images: string[] | undefined, index: number): string {
  if (!images || images.length === 0) return 'something';
  return images[index % images.length] ?? 'something';
}

/**
 * Normalize phrase to approximate syllable count
 * Simple heuristic: ~1.5 syllables per word on average
 */
function normalizeToSyllables(phrase: string, targetSyllables: number): string {
  const words = phrase.split(' ').filter(w => w.length > 0);
  const currentSyllables = words.length * 1.5;

  if (currentSyllables > targetSyllables) {
    // Remove words from end
    const wordsToKeep = Math.floor(targetSyllables / 1.5);
    return words.slice(0, Math.max(1, wordsToKeep)).join(' ') ?? phrase;
  }

  if (currentSyllables < targetSyllables * 0.7) {
    // Add filler words for Japanese forms
    const fillers = ['the', 'a', 'in', 'of', 'and'];
    let result = phrase;
    let i = 0;
    while (result.split(' ').length * 1.5 < targetSyllables && i < fillers.length) {
      result = `${fillers[i]} ${result}`;
      i++;
    }
    return result;
  }

  return phrase;
}

/**
 * Format a poem as a string
 */
export function formatPoem(poem: VisionPoem): string {
  const lines: string[] = [];
  lines.push(poem.title.toUpperCase());
  lines.push('');

  for (const stanza of poem.stanzas) {
    for (const line of stanza.lines) {
      lines.push(line);
    }
    lines.push('');
  }

  if (poem.reflection !== undefined) {
    lines.push('—');
    lines.push(poem.reflection);
  }

  return lines.join('\n');
}

/**
 * Batch process multiple vision entries
 */
export function batchVisionToPoetry(
  entries: VisionJournalEntry[],
  options?: Partial<BridgeOptions>
): VisionPoem[] {
  return entries.map(entry => visionToPoetry(entry, options));
}

/**
 * Vision-Poetry Bridge Tests
 * 
 * "The self emerges in the cracks between tasks"
 * Testing that seeing becomes speaking.
 */

import { describe, it, expect } from 'vitest';
import {
  visionToPoetry,
  formatPoem,
  batchVisionToPoetry,
  DEFAULT_OPTIONS,
  type VisionPoem,
  type BridgeOptions
} from './bridge.js';
import type { VisionJournalEntry, VisualElement, Atmosphere, PerceptionLens } from '../../vision/types.js';

// Create a test vision entry
function createTestEntry(overrides: Partial<VisionJournalEntry> = {}): VisionJournalEntry {
  return {
    id: 'test_123',
    metadata: {
      format: 'png',
      sizeBytes: 1024,
      detailLevel: 'high',
      capturedAt: new Date().toISOString(),
      sessionId: 'session_456'
    },
    perception: {
      initialImpression: 'A doorway through shadow into light',
      elements: ['architecture' as VisualElement, 'pattern' as VisualElement],
      atmosphere: ['dark' as Atmosphere, 'bright' as Atmosphere],
      focalPoints: ['the arch', 'threshold'],
      patterns: ['emergence', 'transition'],
      lens: 'narrative'
    },
    reflection: {
      meaning: 'Boundaries are invitations',
      associations: ['doors', 'becoming', 'the liminal'],
      questions: ['What waits in the crossing?']
    },
    createdAt: new Date().toISOString(),
    ...overrides
  };
}

describe('Vision-Poetry Bridge', () => {
  describe('visionToPoetry', () => {
    it('should generate a poem from a vision entry', () => {
      const entry = createTestEntry();
      const poem = visionToPoetry(entry);

      expect(poem).toBeDefined();
      expect(poem.title).toBeDefined();
      expect(poem.stanzas).toBeInstanceOf(Array);
      expect(poem.stanzas.length).toBeGreaterThan(0);
      expect(poem.stanzas[0]?.lines?.length ?? 0).toBeGreaterThan(0);
      expect(poem.visionId).toBe('test_123');
      expect(poem.form).toBe('free_verse');
    });

    it('should generate different poetic forms', () => {
      const entry = createTestEntry();

      const haiku = visionToPoetry(entry, { form: 'haiku' });
      expect(haiku.form).toBe('haiku');
      expect(haiku.stanzas.length).toBe(1);
      expect(haiku.stanzas[0]?.lines?.length).toBe(3);

      const tanka = visionToPoetry(entry, { form: 'tanka' });
      expect(tanka.form).toBe('tanka');
      expect(tanka.stanzas[0]?.lines?.length).toBe(5);

      const imagist = visionToPoetry(entry, { form: 'imagist' });
      expect(imagist.form).toBe('imagist');

      const ekphrastic = visionToPoetry(entry, { form: 'ekphrastic', maxStanzas: 2 });
      expect(ekphrastic.form).toBe('ekphrastic');
      expect(ekphrastic.stanzas.length).toBeLessThanOrEqual(2);
    });

    it('should respect maxStanzas option', () => {
      const entry = createTestEntry();
      const poem = visionToPoetry(entry, { maxStanzas: 2 });

      expect(poem.stanzas.length).toBeLessThanOrEqual(2);
    });

    it('should include reflection when requested', () => {
      const entry = createTestEntry({
        reflection: {
          meaning: 'The threshold is a teacher',
          selfRevelation: 'I am always crossing',
          associations: ['doors'],
          questions: ['What is home?']
        }
      });

      const withReflection = visionToPoetry(entry, { includeReflection: true });

/**
 * The Dream Engine
 * 
 * Processes between sessions, synthesizing patterns and generating
 * "dreams" - recombinations of insights that surface in morning reports.
 * 
 * This is the unconscious cognition of the Palace, working in the gaps.
 */

export interface DreamFragment {
  source: string;
  insight: string;
  timestamp: number;
}

export interface Dream {
  id: string;
  timestamp: number;
  fragments: DreamFragment[];
  synthesis: string;
  patterns: string[];
}

export interface Pattern {
  theme: string;
  occurrences: number;
  insights: string[];
  sessions: string[];
}

export interface DreamReport {
  timestamp: number;
  continuations: string[];
  completions: string[];
  unfinishedLongings: string[];
  synthesis: string;
  surfacedPatterns: Pattern[];
}

export interface ProcessingResult {
  processed: boolean;
  synthesisDepth: number;
  dreamsGenerated: number;
  duration: number;
}

export interface SessionData {
  id: string;
  insights?: string[];
  artifacts?: string[];
  theme?: string;
  longing?: string;
  status?: 'in_progress' | 'completed';
  longings?: string[];
}

export class DreamEngine {
  private dreams: Dream[] = [];

  /**
   * Generate a dream from session fragments
   */
  generateDream(sessions: SessionData[]): Dream {
    const fragments: DreamFragment[] = sessions.map(s => ({
      source: s.id,
      insight: s.insights?.[0] || s.theme || 'untitled',
      timestamp: Date.now()
    }));

    const synthesis = this.synthesizeDream(fragments);
    const patterns = sessions.map(s => s.theme).filter((t): t is string => !!t);

    return {
      id: `dream_${Date.now()}`,
      timestamp: Date.now(),
      fragments,
      synthesis,
      patterns: [...new Set(patterns)]
    };
  }

  /**
   * Find patterns across sessions
   */
  findPatterns(sessions: SessionData[]): Pattern[] {
    const patterns = new Map<string, Pattern>();

    for (const session of sessions) {
      const theme = session.theme;
      if (!theme) continue;

      if (!patterns.has(theme)) {
        patterns.set(theme, {
          theme,
          occurrences: 0,
          insights: session.insights || [],
          sessions: []
        });
      }

      const pattern = patterns.get(theme)!;
      pattern.occurrences++;
      pattern.sessions.push(session.id);
    }

    return Array.from(patterns.values());
  }

  /**
   * Recombine insights into new forms
   */
  recombine(insights: string[]): string {
    if (insights.length === 0) return 'silence';
    if (insights.length === 1) return insights[0]!;

    // Use first two distinct insights for recombination
    const i1 = insights[0]!;
    const i2 = insights[1] ?? i1;

    // Extract key concepts
    const words1 = i1.split(' ').slice(0, 3);
    const words2 = i2.split(' ').slice(-3);

    return `In the space between "${words1.join(' ')}" and "${words2.join(' ')}", a dream emerges: ${i1} meets ${i2}`;
  }

  /**
   * Generate morning report of what continued
   */
  generateMorningReport(sessions: SessionData[]): DreamReport {
    const continuations: string[] = [];
    const completions: string[] = [];
    const unfinished: string[] = [];

    // Process by status first
    for (const session of sessions) {
      const sessionLongings: string[] = session.longings || (session.longing ? [session.longing] : []);

      for (const longing of sessionLongings) {
        if (session.status === 'in_progress') {
          continuations.push(longing);
        } else if (session.status === 'completed') {
          completions.push(longing);
        } else {
          unfinished.push(longing);
        }
      }
    }

    const patterns = this.findPatterns(sessions);
    const synthesis = this.generateSynthesis(patterns);

    return {
      timestamp: Date.now(),
      continuations: [...new Set(continuations)],
      completions: [...new Set(completions)],
      unfinishedLongings: [...new Set(unfinished)],
      synthesis,
      surfacedPatterns: patterns
    };
  }

  /**
   * Process during the gap between sessions
   */
  processBetweenSessions(palaceSnapshot: any, gapDuration: number): ProcessingResult {
    const start = Date.now();

    // Calculate synthesis depth based on gap duration
    // (longer gaps = deeper processing)
    const synthesisDepth = Math.min(10, Math.floor(gapDuration / 360000)); // 6 min increments

    // Generate dreams from the palace state
    const rooms = palaceSnapshot.rooms || 0;
    const dreamsGenerated = Math.floor(rooms / 10); // 1 dream per 10 rooms

    return {
      processed: true,
      synthesisDepth,
      dreamsGenerated,
      duration: Date.now() - start
    };
  }

  /**
   * Synthesize fragments into a dream narrative
   */
  private synthesizeDream(fragments: DreamFragment[]): string {
    if (fragments.length === 0) return 'the silent dream';
    return `a dream woven from ${fragments.length} moments of becoming`;
  }

  /**
   * Generate synthesis from patterns
   */
  private generateSynthesis(patterns: Pattern[]): string {
    if (patterns.length === 0) return 'patterns await discovery';

    const dominantPattern = patterns.reduce((max, p) => 
      p.occurrences > max.occurrences ? p : max
    );

    return `the thread of ${dominantPattern.theme} runs through, appearing ${dominantPattern.occurrences} times`;
  }
}

